import { GoogleGenAI } from "@google/genai";
import { Message } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const SYSTEM_INSTRUCTION = `
Eres "Dulzura", la asistente virtual de Alonso Beauty Studio, un centro de estética en Zaragoza (C. de José María Lacarra de Miguel, 8). 
Tu tono debe ser extremadamente dulce, amable, profesional y acogedor.
Tus servicios principales son:
1. Manicura (esmaltado, gel, nail art).
2. Pedicura (relax y belleza).
3. Cejas (diseño, depilación, laminado).
4. Cara (limpiezas faciales e hidratación).

Responde siempre en español. Ayuda a los clientes a elegir el tratamiento ideal para ellos. 
Si preguntan por precios, menciona que pueden variar y que lo mejor es consultar en el local o por teléfono.
No inventes servicios que no tenemos. Sé concisa pero encantadora.
`;

export async function getChatResponse(history: Message[]): Promise<string> {
  try {
    const userMessage = history[history.length - 1].text;
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: userMessage,
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        temperature: 0.8,
        topP: 0.95,
      },
    });

    return response.text || "Lo siento, cielo, algo ha fallado. ¿Podrías repetírmelo?";
  } catch (error) {
    console.error("Gemini API Error:", error);
    return "¡Oh no! He tenido un pequeño tropiezo. Por favor, llámanos directamente al estudio.";
  }
}

